import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for issue https://github.com/pinterest/ktlint/issues/1961
 * Indentation of class body when class has multiline super type list (ktlint_official only)
 */
class IndentationRuleClassBodyWithSuperTypeListTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a class without explicit constructor and a multiline super type list then the body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        // With the fix, this code should have no indentation violations
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class without explicit constructor and single super type that spans multiple lines then body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(
                bar1,
                bar2,
            ) {
                // body
            }
            """.trimIndent()
        // Body should not be indented because there's no explicit constructor keyword on new line
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with constructor keyword on same line as class name then body should not be indented`() {
        val code =
            """
            class Foo constructor(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()
        // Constructor on same line as class name - body should not be indented
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a class with explicit constructor on new line then both constructor and body should be indented`() {
        val code =
            """
            class Foo
            constructor(
                foo1: Foo1,
                foo2: Foo2,
            ) : Foobar(
                "foobar1",
                "foobar2",
            ) {
                fun foo() = "foo"
            }
            """.trimIndent()
        val formattedCode =
            """
            class Foo
                constructor(
                    foo1: Foo1,
                    foo2: Foo2,
                ) : Foobar(
                    "foobar1",
                    "foobar2",
                ) {
                    fun foo() = "foo"
                }
            """.trimIndent()
        // When there's explicit constructor on new line, both constructor and body should be indented
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a class with explicit constructor with annotations on new line then both constructor and body should be indented`() {
        val code =
            """
            class Foo
            @Bar1 @Bar2
            constructor(
                foo1: Foo1,
                foo2: Foo2,
            ) : Foobar(
                "foobar1",
                "foobar2",
            ) {
                fun foo() = "foo"
            }
            """.trimIndent()
        val formattedCode =
            """
            class Foo
                @Bar1 @Bar2
                constructor(
                    foo1: Foo1,
                    foo2: Foo2,
                ) : Foobar(
                    "foobar1",
                    "foobar2",
                ) {
                    fun foo() = "foo"
                }
            """.trimIndent()
        // When there's explicit constructor on new line, both constructor and body should be indented
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .isFormattedAs(formattedCode)
    }
}
